#include <stdio.h>
#include <stdlib.h>

#define FRAMES 3
#define REF_STRING_LEN 12

int frames[FRAMES];
int last_used[FRAMES];
int page_faults = 0;
int page_hits = 0;

// Initialize frames to -1 (empty)
void init_frames() {
    for (int i = 0; i < FRAMES; i++) {
        frames[i] = -1;
        last_used[i] = 0;
    }
}

// Check if page is in memory
int is_page_hit(int page) {
    for (int i = 0; i < FRAMES; i++) {
        if (frames[i] == page) {
            last_used[i] = REF_STRING_LEN;  // Reset LRU counter
            return 1;
        }
    }
    return 0;
}

// Find LRU frame to replace
int find_lru_frame() {
    int min_time = last_used[0];
    int lru_index = 0;

    for (int i = 1; i < FRAMES; i++) {
        if (last_used[i] < min_time) {
            min_time = last_used[i];
            lru_index = i;
        }
    }
    return lru_index;
}

void access_page(int page, int time) {
    if (is_page_hit(page)) {
        page_hits++;
        printf("Page %d: HIT\n", page);
    } else {
        page_faults++;
        printf("Page %d: FAULT\n", page);

        // Find empty frame or LRU frame
        int replace_idx = -1;
        for (int i = 0; i < FRAMES; i++) {
            if (frames[i] == -1) {
                replace_idx = i;
                break;
            }
        }

        if (replace_idx == -1) {
            replace_idx = find_lru_frame();
        }

        frames[replace_idx] = page;
        last_used[replace_idx] = time;
    }
}

int main() {
    int ref_string[] = {1, 2, 3, 4, 1, 2, 5, 1, 2, 3, 4, 5};

    init_frames();

    printf("Simulating LRU Page Replacement:\n");
    printf("Frames available: %d\n\n", FRAMES);

    for (int i = 0; i < REF_STRING_LEN; i++) {
        access_page(ref_string[i], i);
    }

    printf("\n--- Results ---\n");
    printf("Page Faults: %d\n", page_faults);
    printf("Page Hits: %d\n", page_hits);

    float fault_rate = (float)page_faults / REF_STRING_LEN;
    printf("Page Fault Rate: %.2f\n", fault_rate);

    if (fault_rate > 0.5) {
        printf("\nWARNING: High fault rate - potential thrashing!\n");
    }

    return 0;
}
